import{_ as s,o as t,c as a,a1 as i}from"./chunks/framework.BwhMLafE.js";const u=JSON.parse('{"title":"Testing","description":"","frontmatter":{},"headers":[],"relativePath":"testing.md","filePath":"testing.md"}'),n={name:"testing.md"};function l(r,e,d,o,p,h){return t(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h1><p>Galley&#39;s repository tests are split into standalone unit suites and a generated-parser matrix. Use typed filters to run the smallest suite that covers a change.</p><h2 id="run-all-tests" tabindex="-1">Run All Tests <a class="header-anchor" href="#run-all-tests" aria-label="Permalink to &quot;Run All Tests&quot;">​</a></h2><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --summary</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> all</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --test-timeout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 30m</span></span></code></pre></div><p>The full command runs build-logic, generator, runtime, generated-parser matrix, and Galley bootstrap-parity tests. The timeout applies to each individual test process, not to the entire build.</p><p><code>--summary all</code> is optional. When provided, it applies directly to the test graph and reports individual test counts; when omitted, Zig uses its normal summary mode.</p><h2 id="test-selectors" tabindex="-1">Test Selectors <a class="header-anchor" href="#test-selectors" aria-label="Permalink to &quot;Test Selectors&quot;">​</a></h2><p>Pass one or more typed selectors with <code>-Dtest-filter</code>:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Dtest-filter=suite:runtime</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Dtest-filter=case:ll-sanbus</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -Dtest-filter=suite:matrix-api</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -Dtest-filter=case:ll-sanbus</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -Dtest-filter=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;name:parse bytes&#39;</span></span></code></pre></div><p>Selectors of the same type are combined with OR. Different selector types are combined with AND. For example, two <code>case:</code> selectors select either case, while adding <code>suite:matrix-api</code> limits both cases to API tests.</p><p>Bare filters such as <code>-Dtest-filter=ll-sanbus</code> are invalid. Use <code>case:ll-sanbus</code> instead.</p><h3 id="suites" tabindex="-1">Suites <a class="header-anchor" href="#suites" aria-label="Permalink to &quot;Suites&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Selector</th><th>Runs</th></tr></thead><tbody><tr><td><code>suite:build</code></td><td>Test-selector and build-logic unit tests</td></tr><tr><td><code>suite:generator</code></td><td>Parser-generator unit tests</td></tr><tr><td><code>suite:runtime</code></td><td>Configuration-independent runtime, ASTNode, and standard-procedure tests</td></tr><tr><td><code>suite:matrix</code></td><td>All generated-parser matrix phases</td></tr><tr><td><code>suite:matrix-compile</code></td><td>Parser generation and production CLI compilation</td></tr><tr><td><code>suite:matrix-api</code></td><td>Generated-parser Zig API tests against language samples</td></tr><tr><td><code>suite:matrix-error</code></td><td>Diagnostic and recovery tests for 16-bit JSON, augmented-JSON, and Sanbus variants</td></tr><tr><td><code>suite:matrix-cli</code></td><td>Generated parser CLI validation against language samples</td></tr><tr><td><code>suite:galley-parity</code></td><td>LL-versus-LR Galley bootstrap output comparison</td></tr></tbody></table><h3 id="cases" tabindex="-1">Cases <a class="header-anchor" href="#cases" aria-label="Permalink to &quot;Cases&quot;">​</a></h3><p>A case is an exact parser-type and language pair, such as <code>case:ll-json</code>, <code>case:lr-json</code>, or <code>case:ll-lua</code>. A <code>case:</code> selector without a <code>suite:</code> selector runs every matrix phase for that case.</p><p>Each selected case is tested across ten parser configurations covering AST, procedures, terminal AST nodes, and 16-bit versus 32-bit input sizes. Cases do not select <code>suite:galley-parity</code>; request that suite explicitly.</p><h3 id="test-names" tabindex="-1">Test Names <a class="header-anchor" href="#test-names" aria-label="Permalink to &quot;Test Names&quot;">​</a></h3><p>Use <code>name:</code> to apply Zig&#39;s test-name substring filtering. It requires an explicit Zig test suite: <code>build</code>, <code>generator</code>, <code>runtime</code>, <code>matrix-api</code>, or <code>matrix-error</code>.</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -Dtest-filter=suite:runtime</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -Dtest-filter=name:dropIfEmpty</span></span></code></pre></div><p>The command fails if the name matches no tests.</p><h2 id="dedicated-steps" tabindex="-1">Dedicated Steps <a class="header-anchor" href="#dedicated-steps" aria-label="Permalink to &quot;Dedicated Steps&quot;">​</a></h2><p>Run the generated-parser matrix or bootstrap parity directly when no standalone suite is needed:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test-generated-parser-matrix</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Dtest-filter=case:ll-json</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test-galley-bootstrap-parity</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Dtest-filter=suite:galley-parity</span></span></code></pre></div><p>Typed filters apply directly to these dedicated steps and follow the same validation rules.</p><h2 id="understanding-matrix-work" tabindex="-1">Understanding Matrix Work <a class="header-anchor" href="#understanding-matrix-work" aria-label="Permalink to &quot;Understanding Matrix Work&quot;">​</a></h2><p>Zig test cases and build checks are reported separately:</p><ul><li>API tests run five Zig test functions for every eligible variant/sample combination.</li><li>Error tests validate fail-fast diagnostics for every 16-bit JSON, augmented-JSON, or Sanbus variant. Focused recovery-enabled LL/LR variants additionally cover multiple diagnostics, limits, recovery windows, and reusable sessions.</li><li>CLI validation runs each eligible sample through the generated executable once.</li><li>Generation and production compilation validate that each selected parser configuration can be generated and built; they are build steps, not additional Zig test cases.</li></ul><p>Samples that exceed a 16-bit parser&#39;s input limit run only on 32-bit configurations.</p>`,28)])])}const k=s(n,[["render",l]]);export{u as __pageData,k as default};
